mapper.select:
SELECT id, email, password, name, phone, age, gender, email_verified,
       nickname, profile_image, role, created_at, is_deleted, provider, provider_id
FROM USER
WHERE email    = #{email}
  AND password = #{password}
  AND is_deleted = 0

mapper.insert:
INSERT INTO USER (
    email, password, name, phone, age, gender, email_verified,
    nickname, profile_image, role,
    created_at, is_deleted, provider, provider_id
) VALUES (
    #{email}, #{password}, #{name}, #{phone}, #{age}, #{gender}, #{emailVerified},
    #{nickname}, #{profileImage}, #{role},
    NOW(), 0, #{provider}, #{providerId}
)

mapper.update:
UPDATE USER SET
    name       = #{name},
    phone      = #{phone},
    nickname   = #{nickname},
    profile_image = #{profileImage}
WHERE id = #{id}
